    val ipsService = mockk<IpsService>()
    val resourcePathProvider = mockk<EvolveResourcePathProvider>()
    val subject = EvolveIcmDataCache(ipsService, resourcePathProvider)

    @Test
    fun `parses base template correctly`() {
        // given
        val path = "icm://bt.wfd".toIcmPath()
        every { ipsService.fileExists(any<IcmPath>()) } returns true
        every { ipsService.wfd2xml(any<IcmPath>()) } returns inputBaseTemplate

        // when
        val result = subject.getOrLoadBaseTemplateData(path)!!

        // then
        result.interactiveFlowNamesToIds.shouldBeEqualTo(mapOf(
            "Letter Content" to "Def.InteractiveFlow0",
            "Flow BT 5" to "Def.InteractiveFlow1",
            "Body Content" to "Def.InteractiveFlow1",
            "Flow BT 7" to "Def.InteractiveFlow2",
            "SMS Content" to "Def.InteractiveFlow2",
        ))
        result.emailFlowId.shouldBeEqualTo("Def.InteractiveFlow1")
        result.smsFlowId.shouldBeEqualTo("Def.InteractiveFlow2")
    }

    @Test
    fun `parses style definition correctly`() {
        // given
        every { resourcePathProvider.getStyleDefinitionPath() } returns "".toIcmPath()
        every { ipsService.fileExists(any<IcmPath>()) } returns true
        every { ipsService.wfd2xml(any<IcmPath>()) } returns inputStyleDefinition

        // when
        val result = subject.styleDefinitionData!!

        // then
        result.textStyleDisplayNamesToNames.size.shouldBeEqualTo(2)
        result.paragraphStyleDisplayNamesToNames.size.shouldBeEqualTo(5)
        result.tableStyleDisplayNamesToName.size.shouldBeEqualTo(0)
        result.textStyleDisplayNamesToNames["headingStyle"].shouldBeEqualTo("iiiheadingStyle")
        result.textStyleDisplayNamesToNames["normalStyle"].shouldBeEqualTo("iiinormalStyle")
        result.paragraphStyleDisplayNamesToNames["paragraphStyle"].shouldBeEqualTo("iiiparagraphStyle")
        result.paragraphStyleDisplayNamesToNames["headingParagraphStyle"].shouldBeEqualTo("iiiheadingParagraphStyle")
        result.paragraphStyleDisplayNamesToNames["compactParagraphStyle"].shouldBeEqualTo("iiicompactParagraphStyle")
        result.paragraphStyleDisplayNamesToNames["spaceParagraphStyle"].shouldBeEqualTo("iiispaceParagraphStyle")
        result.paragraphStyleDisplayNamesToNames["alignRightParagraphStyle"].shouldBeEqualTo("iiialignRightParagraphStyle")
    }
}